let candidate = (() => {
  let pending;
  let instance;
  let callbackStack = [];

  function buildMapping(raw) {
    let mapping = {
      generated: {
        line: raw.generatedLine + 1,
        column: raw.generatedColumn
      }
    };

    if (raw.generatedEndLine !== undefined || raw.generatedEndColumn !== undefined) {
      mapping.generated.end = {
        line: raw.generatedEndLine === undefined ? raw.generatedLine + 1 : raw.generatedEndLine + 1,
        column: (raw.generatedEndColumn === undefined ? raw.generatedColumn : raw.generatedEndColumn) - 1
      };
    }

    if (raw.hasOriginal || raw.source !== undefined || raw.originalLine !== undefined || raw.originalColumn !== undefined) {
      mapping.source = raw.source;
      mapping.original = {
        line: raw.originalLine + 1,
        column: raw.originalColumn
      };
    }

    if (raw.hasName || raw.name !== undefined) {
      mapping.name = raw.name;
    }

    return mapping;
  }

  function normalizeMapping(args) {
    if (args.length === 1 && args[0] && typeof args[0] === "object") {
      return buildMapping(args[0]);
    }

    let [generatedLine, generatedColumn, generatedEndLine, generatedEndColumn, source, originalLine, originalColumn, name, hasOriginal, hasName] = args;
    return buildMapping({
      generatedLine,
      generatedColumn,
      generatedEndLine,
      generatedEndColumn,
      source,
      originalLine,
      originalColumn,
      name,
      hasOriginal,
      hasName
    });
  }

  function dispatchMapping(...args) {
    let active = callbackStack[callbackStack.length - 1];
    if (active) {
      active(normalizeMapping(args));
    }
  }

  async function readBinary() {
    if (typeof candidate.loadBinary === "function") {
      return await candidate.loadBinary();
    }

    if (candidate.binary) {
      return candidate.binary;
    }

    if (typeof WebAssembly.compileStreaming === "function" && candidate.url) {
      return fetch(candidate.url);
    }

    if (candidate.url) {
      return await (await fetch(candidate.url)).arrayBuffer();
    }

    throw new Error("No WebAssembly binary source configured");
  }

  function timed(exports) {
    return new Proxy(exports, {
      get(target, property, receiver) {
        let value = Reflect.get(target, property, receiver);
        if (typeof value !== "function") {
          return value;
        }
        return (...args) => {
          let label = `wasm:${String(property)}`;
          console.time(label);
          try {
            return value.apply(target, args);
          } finally {
            console.timeEnd(label);
          }
        };
      }
    });
  }

  return async function candidate() {
    if (pending) {
      return pending;
    }

    pending = (async () => {
      let imports = {
        env: {
          mapping_callback: dispatchMapping,
          mappingCallback: dispatchMapping
        }
      };

      let binary = await readBinary();
      let result;
      if (binary instanceof Response && typeof WebAssembly.instantiateStreaming === "function") {
        result = await WebAssembly.instantiateStreaming(binary, imports);
      } else if (binary instanceof WebAssembly.Module) {
        result = await WebAssembly.instantiate(binary, imports);
      } else {
        result = await WebAssembly.instantiate(binary, imports);
      }

      instance = result.instance || result;
      let capabilities = timed(instance.exports);

      return {
        instance,
        exports: capabilities,
        capabilities,
        withMappingCallback(callback, operation) {
          callbackStack.push(callback);
          try {
            return operation(capabilities);
          } finally {
            callbackStack.pop();
          }
        }
      };
    })();

    try {
      return await pending;
    } catch (error) {
      pending = undefined;
      instance = undefined;
      throw error;
    }
  };
})();
